import React, { useEffect, useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';

function Dashboard() {
  const [user, setUser] = useState(null);
  const [tasks, setTasks] = useState([]);
  const navigate = useNavigate();

  useEffect(() => {
    fetch('/api/auth/me', { credentials: 'include' })
      .then(res => {
        if (res.status === 401) navigate('/login');
        else return res.json();
      })
      .then(setUser);
    fetch('/api/tasks/')
      .then(res => res.json())
      .then(allTasks => setTasks(allTasks.filter(t => t.assigned_user === (user && user.username))));
  }, [user, navigate]);

  if (!user) return <div>Loading...</div>;

  return (
    <div>
      <h1>Dashboard</h1>
      <p>Username: {user.username}</p>
      <p>World ID Verified: {user.world_id_verified ? 'Yes' : 'No'}</p>
      <p>Fake Balance: {user.fake_balance}</p>
      <h2>Your Tasks</h2>
      <ul>
        {tasks.map(task => (
          <li key={task.id}>{task.description} - {task.status}</li>
        ))}
      </ul>
      <Link to="/">Back to Tasks</Link>
    </div>
  );
}

export default Dashboard;
